func TestSearchWithoutTypeUsesLocalFTS(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	db, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	if _, _, err := db.UpsertBatch("products", []json.RawMessage{
		json.RawMessage(`{"id":"prod_1","name":"Launch Guide","description":"searchable beta guide"}`),
	}); err != nil {
		t.Fatalf("seed products: %v", err)
	}
	db.Close()

	var flags rootFlags
	cmd := newRootCmd(&flags)
	var stdout bytes.Buffer
	var stderr bytes.Buffer
	cmd.SetOut(&stdout)
	cmd.SetErr(&stderr)
	cmd.SetArgs([]string{"search", "Launch", "--data-source=local", "--db", dbPath, "--json"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("search command failed: %v\nstderr: %s", err, stderr.String())
	}

	var envelope struct {
		Results []map[string]any `json:"results"`
		Meta    map[string]any   `json:"meta"`
	}
	if err := json.Unmarshal(stdout.Bytes(), &envelope); err != nil {
		t.Fatalf("unmarshal search output: %v\nstdout: %s", err, stdout.String())
	}
	if len(envelope.Results) != 1 {
		t.Fatalf("results count: want 1, got %d; stdout: %s", len(envelope.Results), stdout.String())
	}
	if envelope.Results[0]["id"] != "prod_1" {
		t.Fatalf("result id: want prod_1, got %#v", envelope.Results[0]["id"])
	}
	if envelope.Meta["source"] != "local" {
		t.Fatalf("meta source: want local, got %#v", envelope.Meta["source"])
	}
}

